import{c as a,Q as t,j as o,m as s}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"How do I add a passkey?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/account/add-passkey.md","filePath":"guide/recipes/account/add-passkey.md","lastUpdated":1779094756000}'),r={name:"guide/recipes/account/add-passkey.md"};function i(n,e,l,d,c,u){return t(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="how-do-i-add-a-passkey" tabindex="-1">How do I add a passkey? <a class="header-anchor" href="#how-do-i-add-a-passkey" aria-label="Permalink to &quot;How do I add a passkey?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p>Anyone — this is on <strong>your own account</strong></p></div><p>Passkeys (WebAuthn) are the strongest second factor: they&#39;re tied to your device or a hardware key, and they&#39;re phishing-resistant.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Account</strong> in the sidebar.</li><li>Scroll to <strong>Security → Authentication Methods</strong>.</li><li>Click <strong>Add Passkey</strong>.</li><li>Your browser shows its native passkey prompt: <ul><li><strong>Touch ID / Windows Hello / Face ID</strong> — biometric on your laptop.</li><li><strong>YubiKey or other security key</strong> — plug in and tap.</li><li><strong>Phone</strong> — scan a QR code if you want to use a passkey from another device.</li></ul></li><li>Follow the prompt to authorise the new credential.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>The passkey appears in your authentication methods list with the device or platform name. You can rename it (&quot;Work YubiKey&quot;, &quot;MacBook&quot;) for clarity.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./enroll-authenticator">How do I enroll an authenticator app?</a></li><li><a href="./reset-mfa">How do I reset my MFA?</a></li></ul>',9)])])}const y=a(r,[["render",i]]);export{p as __pageData,y as default};
